        setFormData(prev => ({ ...prev, ...updates }));
    }, []);

    const handleGroupsChange = useCallback((newGroups: TireGroup[]) => {
        setTireGroups(newGroups);
    }, []);

    const handleDraftChange = useCallback((newDraft: TireGroup | null) => {
        setDraftGroup(newDraft);
