            }

            const existingUrls = sourceClient?.photoUrls || [];
            const finalClientData = { 
                ...dataForSubmission,
                photoUrls: [...new Set([...existingUrls, ...uploadedUrls])]
            };

            let processedClient: Client;

            if (mode === 'edit') {
                setLoadingMessage('Обновление данных...');
